const tls = require('tls');

function createSecureTlsStreams(options = {}) {
  const socket = options.socket;
  if (!socket) throw new Error('options.socket is required');

  const secureContext = options.secureContext || tls.createSecureContext(options);
  const isServer = !!options.isServer;

  const tlsSocket = new tls.TLSSocket(socket, {
    isServer,
    secureContext,
    servername: options.servername,
    requestCert: options.requestCert,
    rejectUnauthorized: options.rejectUnauthorized,
    ALPNProtocols: options.ALPNProtocols,
    SNICallback: options.SNICallback,
    enableTrace: options.enableTrace,
    handshakeTimeout: options.handshakeTimeout,
    session: options.session,
    ticketKeys: options.ticketKeys,
    pskCallback: options.pskCallback,
    pskIdentityHint: options.pskIdentityHint,
    secureOptions: options.secureOptions,
    ciphers: options.ciphers,
    ecdhCurve: options.ecdhCurve,
    dhparam: options.dhparam,
    minVersion: options.minVersion,
    maxVersion: options.maxVersion,
    honorCipherOrder: options.honorCipherOrder,
    cert: options.cert,
    key: options.key,
    ca: options.ca,
    passphrase: options.passphrase,
    crl: options.crl,
    sessionIdContext: options.sessionIdContext,
    secureProtocol: options.secureProtocol,
    sigalgs: options.sigalgs,
    clientCertEngine: options.clientCertEngine,
    privateKeyIdentifier: options.privateKeyIdentifier,
    privateKeyEngine: options.privateKeyEngine,
    ticketKeys: options.ticketKeys
  });

  const cleartext = tlsSocket;

  return {
    encrypted: socket,
    cleartext,
    tlsSocket
  };
}

module.exports = { createSecureTlsStreams };

function parseCertificateSubject(subject) {
  const result = {};
  if (typeof subject !== 'string' || subject.length === 0) return result;

  const parts = subject.split('/').filter(Boolean);

  for (const part of parts) {
    const eqIndex = part.indexOf('=');
    if (eqIndex === -1) continue;

    const key = part.slice(0, eqIndex).trim();
    const value = part.slice(eqIndex + 1).trim();

    if (!key) continue;

    if (Object.prototype.hasOwnProperty.call(result, key)) {
      if (Array.isArray(result[key])) {
        result[key].push(value);
      } else {
        result[key] = [result[key], value];
      }
    } else {
      result[key] = value;
    }
  }

  return result;
}

