class PropSyncComponent extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      value: props.value
    };
  }

  static getDerivedStateFromProps(nextProps, prevState) {
    if (nextProps.value !== prevState.value) {
      return {
        value: nextProps.value
      };
    }
    return null;
  }

  render() {
    return React.createElement("div", null, this.state.value);
  }
}

class ScrollRecorder extends React.Component {
  constructor(props) {
    super(props);
    this.state = {};
    this.scrollPosition = null;
  }

  getSnapshotBeforeUpdate(prevProps, prevState) {
    this.scrollPosition = {
      x: window.scrollX,
      y: window.scrollY
    };
    return this.scrollPosition;
  }

  componentDidUpdate(prevProps, prevState, snapshot) {
    // snapshot contains the scroll position captured before the DOM update
  }

  render() {
    return this.props.children || null;
  }
}

