async function performAsyncOperation(operationName, shouldError = false) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (shouldError) {
        reject(new Error(`Error in ${operationName}: Something went wrong!`));
      } else {
        resolve(`${operationName} completed successfully`);
      }
    }, Math.random() * 1000);
  });
}

