async function checkFileWithClaude(filePath) {
  const messages = [
    {
      role: "user",
      content: `Please check if a file exists at the path: ${filePath}`,
    },
  ];

  let response = await client.messages.create({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    tools: tools,
    messages: messages,
  });

  while (response.stop_reason === "tool_use") {
    const toolUseBlock = response.content.find(
      (block) => block.type === "tool_use"
    );

    if (!toolUseBlock || toolUseBlock.name !== "check_file_exists") {
      break;
    }

    const fileExists = checkFileExists(toolUseBlock.input.file_path);

    messages.push({
      role: "assistant",
      content: response.content,
    });

    messages.push({
      role: "user",
      content: [
        {
          type: "tool_result",
          tool_use_id: toolUseBlock.id,
          content: fileExists ? "File found" : "File not found",
        },
      ],
    });

    response = await client.messages.create({
      model: "claude-3-5-sonnet-20241022",
      max_tokens: 1024,
      tools: tools,
      messages: messages,
    });
  }

  const textBlock = response.content.find((block) => block.type === "text");
  if (textBlock) {
    console.log(textBlock.text);
  }
}

